```rust
use regex::Regex;

fn solve(code: Vec<String>, businessLine: Vec<String>, isActive: Vec<bool>) -> Vec<String> {
    let allowed_business = ["electronics", "grocery", "pharmacy", "restaurant"];
    let code_regex = Regex::new(r"^[a-zA-Z0-9_]+$").unwrap();
    let mut valid_coupons = Vec::new();
    for i in 0..code.len() {
        let c = &code[i];
        let bl = &businessLine[i];
        let active = isActive[i];
        if !c.is_empty() && code_regex.is_match(c) && allowed_business.contains(&bl.as_str()) && active {
            valid_coupons.push((bl.to_string(), c.to_string()));
        }
    }
    valid_coupons.sort_by(|a, b| {
        let order_a = match a.0.as_str() {
            "electronics" => 0,
            "grocery" => 1,
            "pharmacy" => 2,
            "restaurant" => 3,
            _ => panic!("Invalid business line"),
        };
        let order_b = match b.0.as_str() {
            "electronics" => 0,
            "grocery" => 1,
            "pharmacy" => 2,
            "restaurant" => 3,
            _ => panic!("Invalid business line"),
        };
        if order_a != order_b {
            order_a.cmp(&order_b)
        } else {
            a.1.cmp(&b.1)
        }
    });
    valid_coupons.into_iter().map(|(bl, code)| code).collect()
}
```

