}

fn solve(code: Vec<String>, businessLine: Vec<String>, isActive: Vec<bool>) -> Vec<String> {
    let mut valid: Vec<Coupon> = Vec::new();
    let regex = Regex::new(r"^[a-zA-Z0-9_]+$").unwrap();
    let allowed_business = ["electronics", "grocery", "pharmacy", "restaurant"];
    for i in 0..code.len() {
        let c = &code[i];
        let bl = &businessLine[i];
        let active = isActive[i];
        if c.len() > 0 && regex.is_match(c) && allowed_business.contains(&bl.as_str()) && active {
            valid.push(Coupon {
                code: c.clone(),
                business_line: bl.clone(),
            });
        }
