            "pharmacy" => 2,
            "restaurant" => 3,
            _ => panic!("Invalid business line"),
        };
        if order_a != order_b {
            order_a.cmp(&order_b)
        } else {
            a.code.cmp(&b.code)
        }
    });

    valid.into_iter().map(|c| c.code).collect()
}
