  const codeRegex = /^[a-zA-Z0-9_]+$/;
  const businessOrder = {
    'electronics': 0,
    'grocery': 1,
    'pharmacy': 2,
    'restaurant': 3
  };

  for (let i = 0; i < code.length; i++) {
    const c = code[i];
